# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

def connect_to_rabbitmq(host, port):
    return f"http://{host}:{port}"

def create_vhost(rabbitmq_url, vhost_name):
    api_url = f"{rabbitmq_url}/api/vhosts"
    headers = {"Content-Type": "application/json"}
    payload = {"vhost": vhost_name}
    response = requests.post(api_url, headers=headers, json=payload)
    if response.status_code == 201:
        print(f"VHost {vhost_name} created successfully.")
    else:
        print(f"Failed to create VHost {vhost_name}. Status code: {response.status_code}")

def grant_permission(rabbitmq_url, vhost_name, username, permission):
    api_url = f"{rabbitmq_url}/api/permissions/{vhost_name}/{username}"
    headers = {"Content-Type": "application/json"}
    payload = {"permission": permission}
    response = requests.put(api_url, headers=headers, json=payload)
    if response.status_code == 200:
        print(f"Permission granted to {username} in VHost {vhost_name}.")
    else:
        print(f"Failed to grant permission to {username} in VHost {vhost_name}. Status code: {response.status_code}")

def main():
    rabbitmq_url = connect_to_rabbitmq("localhost", 15672)
    vhosts = ["app1_vhost", "app2_vhost", "app3_vhost"]
    users = {"app1_user": "read/write", "app2_user": "write", "app3_user": "read"}

    for vhost in vhosts:
        create_vhost(rabbitmq_url, vhost)

    for user, permission in users.items():
        grant_permission(rabbitmq_url, "app1_vhost", user, permission)
        grant_permission(rabbitmq_url, "app2_vhost", user, permission)
        grant_permission(rabbitmq_url, "app3_vhost", user, permission)

if __name__ == "__main__":
    main()